#include <iostream>
#include <vector>
#include <utility>
using namespace std;

class Solution {
public:
bool checkValid(vector<vector<int>>& matrix, int n) {
	vector<int> counts(n*n);
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			counts[matrix[i][j]]++;
			}
		}
	for (int i = 0; i < n*n; i++) {
		if (counts[i] > 1 || counts[i] == 0) return false;
		}
	return true;
}
};

int main() {
	int n;
	cin >> n;
	vector<vector<int>> matrix(n, vector<int>(n));
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			cin >> matrix[i][j];
			}
		}
	Solution solution;
	cout << (solution.checkValid(matrix, n) ? "True" : "False");
	return 0;
}
